var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_15","text":{"KOREA":"아... 아아...","JPN":"あ……ああ……","ENG":"Ah... ahh...","TWN":"啊……啊啊……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"MINISTRA_CORRUPT_NULL_15","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINISTRA_CORRUPT_NULL_15","text":{"KOREA":"사랑하는... 나의 동생...","JPN":"愛しい……私の妹……","ENG":"My beloved... my little sister...","TWN":"我親愛的……妹妹……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...몇 번을 쏴도 소용 없어요.","JPN":"……何度撃っても無駄です。","ENG":"...No matter how many times you fire, it's useless.","TWN":"……你射再多次也沒用。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"내 언니들이, 저를 위해 당신의 모든 총알을 막아낼 테니까.","JPN":"私のお姉ちゃんたちが、私のためにあなたの弾丸をすべて防ぎますから。","ENG":"My sisters will block every one of your bullets for my sake.","TWN":"我的姐姐們，會替我擋下你所有子彈。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"타기리온. 그때도 당신은 당신의 사도를 대신 희생시켰죠.","JPN":"タギリオン。あの時もあなたは自分の使徒を犠牲にしました。","ENG":"Thagirion. Back then, you sacrificed your Apostles in your place too.","TWN":"塔基里翁。當時你也是讓你的使徒代替你犧牲。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그때의 당신은 무척이나 괴로워했는데... 이젠 아무렇지 않아보이는군요.","JPN":"あの時のあなたはとても辛そうだったけど……もう平気なんですね。","ENG":"Back then, you suffered terribly because of it... but now you don't seem to feel anything at all.","TWN":"那時的你明明非常痛苦……現在卻毫無感覺。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"지금의 전, 그때처럼 어리석은 실수는 하지 않으니까요.","JPN":"今の私は、あの頃のような愚かな間違いは犯しません。","ENG":"The me of now does not make foolish mistakes like that anymore.","TWN":"因為現在的我，不會再犯那樣愚蠢的錯誤了。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그녀들을 사랑하는 마음을... 버렸기 때문인가요?","JPN":"彼女たちを愛する心を……捨てたからですか？","ENG":"Is it because you abandoned your love for them...?","TWN":"那是因為……你捨棄了對她們的愛嗎？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"하하... 버렸냐고?","JPN":"はは……捨てた？","ENG":"Haha... Abandoned it?","TWN":"哈哈……捨棄？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"빼앗겼죠. 당신이 남긴 악마가 말해주지 않았나요?","JPN":"奪われましたよ。あなたが助けた悪魔は話してくれなかったのですか？","ENG":"It was taken from me. Didn't the demon you left behind tell you?","TWN":"是被奪走了。你留下的惡魔沒告訴你嗎？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그래서 되찾아왔죠. 클리포트 게임을 열기 위해선, 조각나지 않은 온전한 제 자신이 필요했거든요.","JPN":"だから取り返して来ました。クリフォトゲームを開くためには、欠けることのない完全な私自身が必要でしたから。","ENG":"So I took it back. To open the Qliphoth Game, I needed my whole self. Unbroken and complete.","TWN":"所以我把它奪回來了。為了開啟逆卡巴拉遊戲，我需要完整的自己。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"모모가... 당신의 조각이라고?","JPN":"モモが……あなたの破片？","ENG":"Momo... is your Fragment?","TWN":"莫莫……是你的碎片？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"맞아요. 제 심장의 일부로서, 이 안에 있어요.","JPN":"そう。私の心臓の一部として、この中にいます。","ENG":"That's right. As a part of my heart, she is inside here.","TWN":"沒錯。作為我心臟的一部分，就在這裡。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"여태 당신을 애타게 찾고 있었지만 지금은 잠잠해요. 당신이 날 쏘는 걸 망설이게 될까 두려워서 숨어있는 거죠.","JPN":"今まで必死にあなたを探していましたが、今は静かですね。あなたが私を撃てなくなることが怖くて隠れているのでしょう。","ENG":"She's been desperately searching for you all this time, but now she's quiet. She's hiding because she's afraid you might hesitate to shoot me.","TWN":"她一直拼命找你，但現在卻安靜下來了。因為害怕讓你在開槍時猶豫而躲起來了。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>틀려...! 이 몸은 모모가 아니다! 타기리온의 파편이다!</color>","JPN":"<color=#ffd34c>違う……！　吾輩はモモではない！　タギリオンの破片だ！</color>","ENG":"<color=#ffd34c>That's wrong...! This is not Momo! It is a Fragment of Thagirion!</color>","TWN":"<color=#ffd34c>錯了……！這具身體不是莫莫！是塔基里翁的碎片！</color>"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모르가나라는 꼬마가 일찍 죽은 탓에...! 그레모리가 그 아일 살리려고 파편을 기생시킨 거다...!</color>","JPN":"<color=#ffd34c>モルガナというガキが早く死んだせいで……！　グレモリーがあの子を助けるために破片を寄生させたのだ……！</color>","ENG":"<color=#ffd34c>Because a child named Morgana died too early...! Gremory made that Fragment parasitize the child's soul to keep her alive...!</color>","TWN":"<color=#ffd34c>因為名叫莫甘娜的小女孩早早死去……葛茉莉為了救她才讓碎片寄生……！</color>"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"...모모?","JPN":"……モモ？","ENG":"...Momo?","TWN":"……莫莫？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모모라는 꼬마는 처음부터 니콜을 만난 적이 없다...! 지금까지 니콜과 함께 살았던 건 악당 타기리온이다...! 니콜은 처음부터 속은 것이다...! 그런 악당을 불쌍하다 생각하고 쏘지 않으면...!</color>","JPN":"<color=#ffd34c>モモという子は最初からニコルに出会っていない……！　今までニコルと暮らしていたのは悪党タギリオンだ……！　ニコルは最初から騙されていた……！　そんな悪人を可哀想だと思って撃たないなら……！</color>","ENG":"<color=#ffd34c>The child called Momo never met Nicole in the first place...! The one who's been living beside Nicole all this time was the villain Thagirion...! Nicole was deceived from the very beginning...! If Nicole pities such a villain and refuses to shoot...!</color>","TWN":"<color=#ffd34c>那個叫莫莫的小孩從一開始就沒見過妮可……！一直陪在妮可身邊的，是反派塔基里翁……！妮可從一開始就被騙了……！如果你因為覺得那個反派可憐而不開槍……！</color>"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그런 니콜은 멍청이인 것이다...!</color>","JPN":"<color=#ffd34c>ニコルはバカなのだ……！</color>","ENG":"<color=#ffd34c>Then Nicole is a fool...!</color>","TWN":"<color=#ffd34c>那妮可就是個笨蛋……！</color>"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...라고 하네요.","JPN":"……と言っています。","ENG":"...So she says.","TWN":"……她是這麼說的。"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"후후... 이런 어설픈 희생정신, 정말 사랑스럽지 않나요?","JPN":"ふふ……こんな中途半端な自己犠牲、本当にかわいらしいと思いませんか？","ENG":"Haha... Isn't that clumsy little sense of self-sacrifice just adorable?","TWN":"呵呵……這種拙劣的犧牲精神，不是很可愛嗎？"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"저 자식이...!","JPN":"あいつ……！","ENG":"Why you...!","TWN":"那傢伙……！"},"stage":{"bg":"ANAPILIS","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"망설여선 안돼.","JPN":"迷うな。","ENG":"You must not hesitate.","TWN":"不能猶豫。"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"잠깐 친하게 지냈다는 이유로, 마왕이란 존재를 네 친구라고 착각한다면...","JPN":"少し仲良くしていただけで、魔王をお前の友だちだと勘違いすると……","ENG":"If you mistake the Demon Lord for your friend just because you spent a little time with her...","TWN":"如果因為短暫的相處，就把魔王當成朋友……"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"그 착각은 비수로 돌아와 널 찌르게 될 거다!","JPN":"その勘違いはお前の命取りになる！","ENG":"That mistake will return as a blade and pierce you!","TWN":"那種錯覺終究會變成利刃刺向你！"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ANAPILIS","slots":{"L":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"니콜... 미안...","JPN":"ニコル……ごめんね……","ENG":"Nicole... I'm sorry...","TWN":"妮可…對不起…"},"stage":{"bg":"GREMORY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"모모가... 더 잘 할 테니까...","JPN":"モモが……頑張るから……","ENG":"Momo will behave nicely...","TWN":"莫莫…以後會乖…"},"stage":{"bg":"GREMORY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"혼자서... 주스 잘 마실 테니까...","JPN":"一人で……ジュースを飲めるようになるから……","ENG":"I'll get juice on my own...","TWN":"莫莫…會自己倒果汁…"},"stage":{"bg":"GREMORY_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_01","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};